import { AlertOptions } from "./alertOptions";
import { AbstractBasicAlert } from "./basicAlert";

/**
 * Timer 類型的訊息窗。
 */
export class TimerAlert extends AbstractBasicAlert {
  /**
   * 顯示成功訊息，時間到會自動關閉訊息窗。
   * @param {string} [msg = ""] 成功訊息，應簡短扼要。
   * @param {Object} [options = {}] 可另外給予自訂的 SweetAlert2 的設定。
   */
  static alertSuccess(msg = "", options = {}) {
    this.sucessAlert.fire({
      ...AlertOptions.timer,
      ...options,
      title: msg,
    });
  }

  /**
   * 顯示錯誤訊息，時間到會自動關閉訊息窗。
   * @param {string} [msg = ""] 錯誤訊息，應簡短扼要。
   * @param {Object} [options = {}] 可另外給予自訂的 SweetAlert2 的設定。
   */
  static alertError(msg = "", options = {}) {
    this.errorAlert.fire({
      ...AlertOptions.timer,
      ...options,
      title: msg,
    });
  }
}
